"use client"

import * as React from "react"
import {
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Container,
  type CoSignValue,
  DataTable,
  DistributionBar,
  Drawer,
  DrawerClose,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
  Grid,
  Meter,
  Rating,
  Separator,
  Statistic,
  type WorkflowValue,
  formatNumber,
} from "@gunjo/ui"
import type { ColumnDef } from "@gunjo/ui"
import { IconCalendarClock, IconChevronRight, IconX } from "@tabler/icons-react"

import {
  type Employee,
  GRADE_BADGE,
  GRADE_ORDER,
  GRADE_TONE,
  type RatingGrade,
  cycle,
  cycleProgress,
  employees,
  gradeDistribution,
} from "./data"
import { EvaluationDetail } from "./EvaluationDetail"
import { PersonCell } from "./PersonCell"

const STAGE_LABEL: Record<string, string> = {
  self: "自己評価",
  primary: "一次評価",
  secondary: "二次評価",
  hr: "人事確定",
}

const ACTOR_ID = "hr-ono" // ログイン中の人事担当（デモ）

function StageBadge({ employee }: { employee: Employee }) {
  if (employee.workflowStatus === "approved") return <Badge variant="success">確定済み</Badge>
  if (employee.workflowStatus === "rejected") return <Badge variant="destructive">差戻し</Badge>
  return <Badge variant="info">{STAGE_LABEL[employee.currentStageId]}中</Badge>
}

export default function PerformanceReviewPage() {
  const progress = cycleProgress()
  const dist = gradeDistribution()

  // ドリルイン対象 + ワークフロー/2人確認の状態（被評価者ごと）
  const [selectedId, setSelectedId] = React.useState<string | null>(null)
  const [workflows, setWorkflows] = React.useState<Record<string, WorkflowValue>>(() =>
    Object.fromEntries(
      employees.map((e) => [
        e.id,
        { currentStageId: e.currentStageId, status: e.workflowStatus, records: e.records as WorkflowValue["records"] },
      ]),
    ),
  )
  const [coSigns, setCoSigns] = React.useState<Record<string, CoSignValue>>({})

  const selected = employees.find((e) => e.id === selectedId) ?? null

  const distSegments = GRADE_ORDER.map((g) => ({
    label: `${g}（${dist[g]}名）`,
    value: dist[g],
    color: GRADE_TONE[g],
  }))

  const columns: ColumnDef<Employee>[] = [
    {
      id: "person",
      header: "被評価者",
      cell: ({ row }) => (
        <PersonCell
          name={row.original.name}
          secondary={`${row.original.dept}`}
          tertiary={row.original.role}
          avatarColor={row.original.avatarColor}
        />
      ),
    },
    {
      id: "grade",
      header: "等級",
      cell: ({ row }) => <span className="text-sm tabular-nums">{row.original.grade}</span>,
    },
    {
      id: "progress",
      header: "目標達成度",
      cell: ({ row }) => {
        const wp =
          row.original.goals.reduce((s, g) => s + (g.selfProgress * g.weight) / 100, 0)
        return (
          <div className="w-32">
            <Meter
              value={Math.round(wp)}
              max={100}
              target={100}
              direction="higher-is-better"
              unit="%"
              size="inline"
              label={`${row.original.name} の加重達成度`}
            />
          </div>
        )
      },
    },
    {
      id: "stage",
      header: "ワークフロー",
      cell: ({ row }) => <StageBadge employee={row.original} />,
    },
    {
      id: "score",
      header: "総合 / 評語",
      cell: ({ row }) => (
        <div className="flex items-center gap-2">
          <Rating value={row.original.overallScore} showValue size="sm" label={`総合 ${row.original.overallScore} / 5`} />
          <Badge variant={GRADE_BADGE[row.original.finalGrade]}>{row.original.finalGrade}</Badge>
        </div>
      ),
    },
    {
      id: "open",
      header: "",
      cell: () => (
        <span className="inline-flex items-center text-muted-foreground">
          <IconChevronRight className="h-4 w-4" aria-hidden />
        </span>
      ),
    },
  ]

  return (
    <Container size="2xl" className="py-6 sm:py-8">
      <div className="flex flex-col gap-6">
        {/* ページヘッダ */}
        <header className="flex flex-col gap-2">
          <p className="text-sm text-muted-foreground">人事評価 / 目標管理</p>
          <div className="flex flex-wrap items-end justify-between gap-3">
            <div>
              <h1 className="text-2xl font-bold tracking-tight text-foreground">{cycle.name}</h1>
              <p className="mt-1 inline-flex items-center gap-1.5 text-sm text-muted-foreground">
                <IconCalendarClock className="h-4 w-4" aria-hidden />
                評価期間 {cycle.periodLabel} ・ 対象者 {cycle.targetCount}名
              </p>
            </div>
            <div className="flex items-center gap-2">
              <Badge variant="warning">自己評価締切 {cycle.selfDeadline}</Badge>
              <Badge variant="outline">確定締切 {cycle.finalDeadline}</Badge>
            </div>
          </div>
        </header>

        {/* サマリ指標 */}
        <Grid cols={{ base: 2, md: 3, lg: 6 }} gap={3}>
          <Card><CardContent className="p-4"><Statistic label="対象者" value={`${progress.total}名`} /></CardContent></Card>
          <Card><CardContent className="p-4"><Statistic label="提出率" value={`${progress.submittedRate}%`} change={`${progress.submitted}/${progress.total}`} trend="up" tone="positive" /></CardContent></Card>
          <Card><CardContent className="p-4"><Statistic label="一次完了" value={`${progress.primaryDone}名`} hint="一次評価以降" /></CardContent></Card>
          <Card><CardContent className="p-4"><Statistic label="確定" value={`${progress.finalized}名`} hint="人事確定済み" /></CardContent></Card>
          <Card><CardContent className="p-4"><Statistic label="平均スコア" value={progress.avgScore.toFixed(2)} hint="/ 5.0" /></CardContent></Card>
          <Card><CardContent className="p-4"><Statistic label="未提出" value={`${progress.total - progress.submitted}名`} trend={progress.total - progress.submitted > 0 ? "down" : "flat"} tone={progress.total - progress.submitted > 0 ? "negative" : "neutral"} /></CardContent></Card>
        </Grid>

        {/* 進捗 + 分布 */}
        <Grid cols={{ base: 1, lg: 2 }} gap={4}>
          <Card>
            <CardHeader className="pb-3">
              <CardTitle as="h2" className="text-base">サイクル進捗</CardTitle>
              <CardDescription>自己評価提出 → 一次 → 二次 → 人事確定</CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-4">
              {[
                { label: "自己評価 提出", done: progress.submitted },
                { label: "一次評価 完了", done: progress.primaryDone },
                { label: "人事確定", done: progress.finalized },
              ].map((row) => (
                <div key={row.label} className="flex flex-col gap-1.5">
                  <div className="flex items-center justify-between text-sm">
                    <span className="text-foreground">{row.label}</span>
                    <span className="tabular-nums text-muted-foreground">{row.done} / {progress.total}</span>
                  </div>
                  <Meter
                    value={row.done}
                    max={progress.total}
                    direction="fill-is-good"
                    size="sm"
                    label={`${row.label}: ${row.done} / ${progress.total}`}
                    formatValue={(v) => formatNumber(v)}
                  />
                </div>
              ))}
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-3">
              <CardTitle as="h2" className="text-base">評価分布（キャリブレーション）</CardTitle>
              <CardDescription>S/A/B/C/D の人数で甘辛をチェック</CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-4">
              <DistributionBar segments={distSegments} showLegend formatValue={(v) => `${v}名`} totalLabel="対象" />
              <Separator />
              <Grid cols={5} gap={2}>
                {GRADE_ORDER.map((g) => (
                  <div key={g} className="flex flex-col items-center rounded-md border bg-card p-2">
                    <Badge variant={GRADE_BADGE[g]}>{g}</Badge>
                    <span className="mt-1 text-lg font-semibold tabular-nums">{dist[g]}</span>
                    <span className="text-[11px] text-muted-foreground">名</span>
                  </div>
                ))}
              </Grid>
            </CardContent>
          </Card>
        </Grid>

        {/* 被評価者一覧 */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle as="h2" className="text-base">被評価者一覧</CardTitle>
            <CardDescription>行を選択すると評価詳細・ワークフローを開きます</CardDescription>
          </CardHeader>
          <CardContent>
            <DataTable
              columns={columns}
              data={employees}
              filter={null}
              pageSize={10}
              onRowClick={(row) => setSelectedId(row.id)}
              renderCard={(row) => (
                <button
                  type="button"
                  onClick={() => setSelectedId(row.id)}
                  className="flex w-full flex-col gap-3 rounded-lg border bg-card p-4 text-left"
                >
                  <PersonCell
                    name={row.name}
                    secondary={row.dept}
                    tertiary={`${row.role} ・ 等級 ${row.grade}`}
                    avatarColor={row.avatarColor}
                    trailing={<StageBadge employee={row} />}
                  />
                  <div className="flex items-center justify-between">
                    <Rating value={row.overallScore} showValue size="sm" label={`総合 ${row.overallScore} / 5`} />
                    <Badge variant={GRADE_BADGE[row.finalGrade]}>評語 {row.finalGrade}</Badge>
                  </div>
                  <Meter
                    value={Math.round(row.goals.reduce((s, g) => s + (g.selfProgress * g.weight) / 100, 0))}
                    max={100}
                    target={100}
                    direction="higher-is-better"
                    unit="%"
                    size="inline"
                    label={`${row.name} の加重達成度`}
                  />
                </button>
              )}
            />
          </CardContent>
        </Card>
      </div>

      {/* 評価詳細ドロワー */}
      <Drawer open={selected !== null} onOpenChange={(o) => { if (!o) setSelectedId(null) }}>
        <DrawerContent side="right" className="ml-auto h-full w-full max-w-xl">
          {selected ? (
            <>
              <DrawerHeader className="flex flex-row items-center justify-between border-b">
                <DrawerTitle className="text-base">評価詳細 — {selected.name}</DrawerTitle>
                <DrawerClose asChild>
                  <Button variant="ghost" size="icon" aria-label="閉じる">
                    <IconX className="h-4 w-4" />
                  </Button>
                </DrawerClose>
              </DrawerHeader>
              <div className="min-h-0 flex-1 overflow-y-auto p-4 sm:p-6">
                <EvaluationDetail
                  employee={selected}
                  value={workflows[selected.id]}
                  onWorkflowChange={(next) =>
                    setWorkflows((prev) => ({ ...prev, [selected.id]: next }))
                  }
                  coSign={coSigns[selected.id]}
                  onCoSign={(next) =>
                    setCoSigns((prev) => ({ ...prev, [selected.id]: next }))
                  }
                  actorId={ACTOR_ID}
                />
              </div>
            </>
          ) : null}
        </DrawerContent>
      </Drawer>
    </Container>
  )
}

"use client"

import * as React from "react"
import { Avatar, AvatarFallback, cn } from "@gunjo/ui"

/**
 * PersonCell — avatar + 氏名 + 部署/役割 (+ optional 補足/ステータス).
 *
 * HAND-ROLLED. @gunjo/ui ships `Avatar` (Radix Root/Image/Fallback) and
 * `AvatarGroup`, but NO "person / identity / media-object" cell that pairs an
 * avatar with a name + secondary line. This exact cell appears for every
 * 被評価者 (table rows) and every 評価者 (detail comments), so we assemble it once
 * here. A `<Person avatar name secondary />` primitive in @gunjo/ui would have
 * removed this file entirely.
 */

function initials(name: string): string {
  // 日本語氏名: 姓の頭1文字（スペース区切りの最初のトークン先頭）
  const first = name.trim().split(/\s+/)[0] ?? name
  return first.slice(0, 1)
}

export interface PersonCellProps {
  name: string
  secondary?: React.ReactNode
  tertiary?: React.ReactNode
  avatarColor?: string
  size?: "sm" | "md"
  trailing?: React.ReactNode
  className?: string
}

export function PersonCell({
  name,
  secondary,
  tertiary,
  avatarColor,
  size = "md",
  trailing,
  className,
}: PersonCellProps) {
  const avatarSize = size === "sm" ? "h-8 w-8" : "h-10 w-10"
  return (
    <div className={cn("flex min-w-0 items-center gap-3", className)}>
      <Avatar className={avatarSize}>
        <AvatarFallback className={cn("text-sm font-semibold", avatarColor)}>
          {initials(name)}
        </AvatarFallback>
      </Avatar>
      <div className="min-w-0 flex-1">
        <div className={cn("truncate font-medium text-foreground", size === "sm" ? "text-sm" : "text-sm")}>
          {name}
        </div>
        {secondary ? (
          <div className="truncate text-xs text-muted-foreground">{secondary}</div>
        ) : null}
        {tertiary ? (
          <div className="truncate text-xs text-muted-foreground">{tertiary}</div>
        ) : null}
      </div>
      {trailing ? <div className="shrink-0">{trailing}</div> : null}
    </div>
  )
}
